// frontend/src/pages/RegisterPage.js
import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import API from '../api/axios';

const RegisterPage = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    dob: '',
    level: '',
    museumType: '',
    terms: false,
  });

  const [showPassword, setShowPassword]           = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [error, setError]   = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  // Password strength criteria
  const passwordCriteria = {
    length: formData.password.length >= 8,
    upper:  /[A-Z]/.test(formData.password),
    lower:  /[a-z]/.test(formData.password),
    number: /[0-9]/.test(formData.password),
  };

  const handleChange = (e) => {
    const { id, name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [type === 'checkbox' ? 'terms' : name || id]: type === 'checkbox' ? checked : value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (formData.password !== formData.confirmPassword) {
      return setError('Passwords do not match.');
    }
    if (!formData.terms) {
      return setError('You must agree to the terms and conditions.');
    }

    setLoading(true);
    try {
      const { data } = await API.post('/auth/register', {
        name:     formData.name,
        email:    formData.email,
        password: formData.password,
      });
      localStorage.setItem('token', data.token);
      navigate('/home');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="content">
      <h2>Sign Up</h2>

      {error && (
        <p style={{
          color: '#7a1a1a',
          background: 'rgba(180,60,60,0.12)',
          border: '1px solid #b43c3c',
          borderRadius: '8px',
          padding: '10px 16px',
          marginBottom: '16px',
          textAlign: 'center',
        }}>
          {error}
        </p>
      )}

      <form id="registrationForm" onSubmit={handleSubmit}>
        <p>Do you want to join me? Fill up this form to register and stay updated.</p>

        <label htmlFor="name">Full Name:</label>
        <input
          type="text"
          id="name"
          placeholder="e.g., Maica Doctolero"
          value={formData.name}
          onChange={handleChange}
          required
        />

        <label htmlFor="email">Email Address:</label>
        <input
          type="email"
          id="email"
          placeholder="e.g., maica@gmail.com"
          value={formData.email}
          onChange={handleChange}
          required
        />

        <label htmlFor="password">Password:</label>
        <div className="password-wrapper" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <input
            type={showPassword ? 'text' : 'password'}
            id="password"
            placeholder="Enter strong password"
            value={formData.password}
            onChange={handleChange}
            style={{ flex: 1, margin: 0 }}
          />
          <button
            type="button"
            className="toggle-btn"
            onClick={() => setShowPassword(!showPassword)}
            style={{ padding: '10px', background: 'none', border: '1px solid #d2b48c', borderRadius: '4px', cursor: 'pointer' }}
          >
            {showPassword ? '🙈' : '👁️'}
          </button>
        </div>

        {/* Password Requirements */}
        <ul className="req-list" style={{ listStyle: 'none', padding: '8px 0', margin: '4px 0 12px' }}>
          {[
            { key: 'length', label: 'At least 8 characters' },
            { key: 'upper',  label: 'At least one uppercase letter' },
            { key: 'lower',  label: 'At least one lowercase letter' },
            { key: 'number', label: 'At least one number' },
          ].map(({ key, label }) => (
            <li
              key={key}
              style={{
                color: passwordCriteria[key] ? '#2D4A0E' : '#8C7E72',
                fontSize: '0.88rem',
                marginBottom: '2px',
              }}
            >
              {passwordCriteria[key] ? '✓' : '○'} {label}
            </li>
          ))}
        </ul>

        <label htmlFor="confirmPassword">Confirm Password:</label>
        <div className="password-wrapper" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <input
            type={showConfirmPassword ? 'text' : 'password'}
            id="confirmPassword"
            placeholder="Re-type password"
            value={formData.confirmPassword}
            onChange={handleChange}
            style={{ flex: 1, margin: 0 }}
          />
          <button
            type="button"
            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
            style={{ padding: '10px', background: 'none', border: '1px solid #d2b48c', borderRadius: '4px', cursor: 'pointer' }}
          >
            {showConfirmPassword ? '🙈' : '👁️'}
          </button>
        </div>

        <label htmlFor="dob">Date of Birth:</label>
        <input
          type="date"
          id="dob"
          value={formData.dob}
          onChange={handleChange}
        />

        <label>Traveler Level:</label>
        <div className="radio-group" style={{ margin: '8px 0 12px' }}>
          {['beginner', 'intermediate', 'expert'].map(lvl => (
            <React.Fragment key={lvl}>
              <input
                type="radio"
                name="level"
                value={lvl}
                id={lvl}
                checked={formData.level === lvl}
                onChange={handleChange}
              />
              <label style={{ display: 'inline', marginRight: '16px' }} htmlFor={lvl}>
                {lvl.charAt(0).toUpperCase() + lvl.slice(1)}
              </label>
            </React.Fragment>
          ))}
        </div>

        <label htmlFor="museumType">Favorite Museum Type:</label>
        <select id="museumType" value={formData.museumType} onChange={handleChange}>
          <option value="">Select Type</option>
          <option value="history">History</option>
          <option value="art">Art</option>
          <option value="science">Science</option>
        </select>

        <div style={{ margin: '20px 0' }}>
          <input
            type="checkbox"
            id="terms"
            checked={formData.terms}
            onChange={handleChange}
          />
          <label style={{ display: 'inline' }} htmlFor="terms">
            {' '}I agree to the terms and conditions.
          </label>
        </div>

        <input
          type="submit"
          id="newcolor"
          value={loading ? 'Registering...' : 'Register Now'}
          disabled={loading}
        />
      </form>

      <p style={{ marginTop: '20px', textAlign: 'center' }}>
        Already have an account? <Link to="/login" style={{ color: '#475522', fontWeight: 'bold' }}>Login here</Link>
      </p>
    </div>
  );
};

export default RegisterPage;
